function VideoCard() {

  const [modal, setModal] = useState(false);
  const [videoLoading, setVideoLoading] = useState(true);

  function openModal(){
    setModal(!modal);
  };

  return (
  <div
    onClick={openModal}/*this will be your element to click to open*/
    className="">
      {modal ? (/*this is a ternary to show the modal or not*/
          <section className="">
            <div className="">
              <div className="" modal={modal}>
                <button
                  className=""
                  onClick={setModal}/*This closes the modal*/
                >X</button>
                <div className="">
                  {/*the text you copied from youtube goes here*/}
                </div>
              </div>
            </div>
          </section>
        ) : null}/*this sets the modal to be invisible if it isn't active*/
    </div>
  );
}

export default VideoCard;
